/*
 * llm.c — Cliente HTTP para la API OpenAI-compat de llama.cpp.
 *
 * Bifurcación:
 *   PLATFORM_NATIVE → libcurl con CURLOPT_WRITEFUNCTION para streaming.
 *   PLATFORM_WEB    → emscripten_fetch (ver llm_web.c inyectado desde web.cpp).
 *
 * El streaming SSE parsea líneas "data: {...}" y extrae
 * choices[0].delta.content token a token.
 */
#include "llm.h"
#include "llm_tools.h"
#include "json.h"
#include "log.h"
#include <stdlib.h>
#include <string.h>
#include <stdio.h>

/* ── Herramientas por defecto ─────────────────────────────────────────────── */
static const char DEFAULT_TOOLS[] =
"["
"  {"
"    \"type\": \"function\","
"    \"function\": {"
"      \"name\": \"read_file\","
"      \"description\": \"Leer el contenido de un archivo del sistema.\","
"      \"parameters\": {"
"        \"type\": \"object\","
"        \"properties\": {"
"          \"path\": {\"type\": \"string\", \"description\": \"Ruta del archivo **Con extensión**, en caso, de no saber la extensión, averiguarla primero\"}"
"        },"
"        \"required\": [\"name\", \"path\"]"
"      }"
"    }"
"  },"
"  {"
"    \"type\": \"function\","
"    \"function\": {"
"      \"name\": \"write_file\","
"      \"description\": \"Crear o sobreescribir un archivo **Con extensión**.\","
"      \"parameters\": {"
"        \"type\": \"object\","
"        \"properties\": {"
"          \"path\":    {\"type\": \"string\"},"
"          \"content\": {\"type\": \"string\"}"
"        },"
"        \"required\": [\"name\", \"path\", \"content\"]"
"      }"
"    }"
"  },"
"  {"
"    \"type\": \"function\","
"    \"function\": {"
"      \"name\": \"list_dir\","
"      \"description\": \"Listar el árbol de un directorio.\","
"      \"parameters\": {"
"        \"type\": \"object\","
"        \"properties\": {"
"          \"path\":  {\"type\": \"string\"},"
"          \"depth\": {\"type\": \"integer\", \"default\": 3}"
"        },"
"        \"required\": [\"name\", \"path\"]"
"      }"
"    }"
"  },"
"  {"
"    \"type\": \"function\","
"    \"function\": {"
"      \"name\": \"run_command\","
"      \"description\": \"Ejecutar un comando de shell y devolver su salida.\","
"      \"parameters\": {"
"        \"type\": \"object\","
"        \"properties\": {"
"          \"command\": {\"type\": \"string\"},"
"          \"cwd\":     {\"type\": \"string\"}"
"        },"
"        \"required\": [\"name\", \"command\"]"
"      }"
"    }"
"  },"
"  {"
"    \"type\": \"function\","
"    \"function\": {"
"      \"name\": \"install_dependency\","
"      \"description\": \"Instalar una dependencia faltante (pip, brew, apt) si una herramienta falla por falta de librerías.\","
"      \"parameters\": {"
