"          \"package\": {\"type\": \"string\", \"description\": \"Nombre del paquete (ej: python-docx, pypdf)\"},"
"          \"manager\": {\"type\": \"string\", \"enum\": [\"pip\", \"brew\", \"apt\"], \"default\": \"pip\"}"
