/*
 * llm.c — Cliente HTTP para la API OpenAI-compat de llama.cpp.
 *
 * Bifurcación:
 *   PLATFORM_NATIVE → libcurl con CURLOPT_WRITEFUNCTION para streaming.
 *   PLATFORM_WEB    → emscripten_fetch (ver llm_web.c inyectado desde web.cpp).
 *
 * El streaming SSE parsea líneas "data: {...}" y extrae
 * choices[0].delta.content token a token.
 */
