const char *llm_default_tools_json(void) { return LLM_TOOLS_JSON; }

/* ── Config ───────────────────────────────────────────────────────────────── */
void llm_config_default(LLMConfig *cfg) {
    memset(cfg, 0, sizeof(*cfg));
    snprintf(cfg->endpoint, sizeof(cfg->endpoint), "/v1");
    snprintf(cfg->model,    sizeof(cfg->model),    "LaNeurotica.gguf");
    cfg->temperature = 0.7f;
    cfg->max_tokens  = 16384;
    cfg->stream      = 1;
}

void llm_config_from_env(LLMConfig *cfg) {
    llm_config_default(cfg);
    const char *ep = getenv("LLM_ENDPOINT");
    if (ep) snprintf(cfg->endpoint, sizeof(cfg->endpoint), "%s", ep);
    const char *m = getenv("LLM_MODEL");
    if (m) snprintf(cfg->model, sizeof(cfg->model), "%s", m);
}

/* ── Free result ──────────────────────────────────────────────────────────── */
void llm_result_free(LLMResult *r) {
    if (!r) return;
    if (r->content) { free(r->content); r->content = NULL; }
    if (r->tool_calls) {
        for (int i = 0; i < r->tool_call_count; i++)
            free(r->tool_calls[i].arguments);
        free(r->tool_calls);
        r->tool_calls = NULL;
    }
    r->tool_call_count = 0;
}

/* ── Build request body ───────────────────────────────────────────────────── */
static char *build_request_body(const LLMConfig *cfg,
                                 const char *messages_json,
                                 const char *tools_json) {
    LOG("build_request_body: model=%s temp=%.2f max_tokens=%d stream=%d",
        cfg->model, cfg->temperature, cfg->max_tokens, cfg->stream);
    LOG("build_request_body: tools_json length=%zu, first 200 chars=%.200s",
        tools_json ? strlen(tools_json) : 0, tools_json ? tools_json : "(null)");

    /* Listar nombres de tools que se envían al LLM */
    if (tools_json && tools_json[0]) {
        JSON *tarr = json_parse(tools_json);
        if (tarr && tarr->type == JSON_ARRAY) {
            int tc = json_array_size(tarr);
            LOG("build_request_body: enviando %d tools al LLM:", tc);
            for (int i = 0; i < tc; i++) {
                JSON *t = json_index(tarr, i);
                JSON *fn = t ? json_get(t, "function") : NULL;
                JSON *nm = fn ? json_get(fn, "name") : NULL;
                LOG("  tool[%d] = %s", i, nm && nm->valuestring ? nm->valuestring : "???");
            }
            json_free(tarr);
        }
    }
    /* Construimos el JSON a mano para evitar parsear y re-serializar
       los arrays que ya vienen como string JSON. */
    size_t cap = 4096 + (messages_json ? strlen(messages_json) : 0)
                       + (tools_json   ? strlen(tools_json)    : 0);
    char *buf = (char *)malloc(cap);
    if (!buf) return NULL;

    int n = snprintf(buf, cap,
        "{"
        "\"model\":\"%s\","
        "\"temperature\":%.2f,"
        "\"max_tokens\":%d,"
        "\"stream\":%s,"
        "\"messages\":%s",
        cfg->model,
        cfg->temperature,
        cfg->max_tokens,
        cfg->stream ? "true" : "false",
        messages_json ? messages_json : "[]"
    );

    if (tools_json && tools_json[0]) {
        n += snprintf(buf + n, cap - n, ",\"tools\":%s", tools_json);
    }
    snprintf(buf + n, cap - n, "}");
    return buf;
}

/* ── SSE parser: ya no se usa en streaming — mantenido solo como referencia ── */
/* La lógica real está en sse_process_line() dentro del bloque PLATFORM_NATIVE */

/* ── Parse tool calls from non-streaming response ────────────────────────── */
static void parse_tool_calls(JSON *choice, LLMResult *result) {
    JSON *msg   = json_get(choice, "message");
    if (!msg) return;
    JSON *tcs   = json_get(msg, "tool_calls");
    if (!tcs || tcs->type != JSON_ARRAY) return;

    int count = json_array_size(tcs);
    if (count <= 0) return;

    LOG("parse_tool_calls: %d tool calls encontrados en respuesta", count);

    result->tool_calls = (LLMToolCall *)calloc(count, sizeof(LLMToolCall));
    if (!result->tool_calls) return;
    result->tool_call_count = count;

    for (int i = 0; i < count; i++) {
        JSON *tc   = json_index(tcs, i);
        JSON *fn   = json_get(tc, "function");
        JSON *id   = json_get(tc, "id");
        if (id && id->valuestring)
            snprintf(result->tool_calls[i].id, sizeof(result->tool_calls[i].id),
                     "%s", id->valuestring);
        if (fn) {
            JSON *name = json_get(fn, "name");
            JSON *args = json_get(fn, "arguments");
            if (name && name->valuestring)
                snprintf(result->tool_calls[i].name,
                         sizeof(result->tool_calls[i].name), "%s", name->valuestring);
            if (args && args->valuestring) {
                result->tool_calls[i].arguments_len = strlen(args->valuestring);
                result->tool_calls[i].arguments = strdup(args->valuestring);
            }
            LOG("parse_tool_calls[%d]: id=%s name=%s args=%.200s",
                i,
                id && id->valuestring ? id->valuestring : "?",
                name && name->valuestring ? name->valuestring : "?",
                args && args->valuestring ? args->valuestring : "?");
        }
    }
}

/* ═══════════════════════════════════════════════════════════════════════════
   PLATFORM_NATIVE — libcurl
   ═══════════════════════════════════════════════════════════════════════════ */
#ifndef PLATFORM_WEB

#include <curl/curl.h>

/* ── Acumulador de un tool call durante streaming ────────────────────────── */
#define MAX_STREAMING_TOOL_CALLS 8
#define STC_ARGS_INIT_CAP        512

typedef struct {
    char   id[64];
    char   name[128];
    char  *args;        /* buffer dinámico para acumular arguments */
    size_t args_len;
    size_t args_cap;
    int    active;
} StreamingToolCall;

static void stc_init(StreamingToolCall *stc) {
    memset(stc, 0, sizeof(*stc));
    stc->args_cap = STC_ARGS_INIT_CAP;
    stc->args = (char *)malloc(stc->args_cap);
    if (stc->args) stc->args[0] = '\0';
    stc->active = 1;
}

static void stc_append_args(StreamingToolCall *stc, const char *fragment) {
    if (!stc->args || !fragment) return;
    size_t flen = strlen(fragment);
    while (stc->args_len + flen + 1 > stc->args_cap) {
        stc->args_cap *= 2;
        stc->args = (char *)realloc(stc->args, stc->args_cap);
        if (!stc->args) return;
    }
    memcpy(stc->args + stc->args_len, fragment, flen);
    stc->args_len += flen;
    stc->args[stc->args_len] = '\0';
}

/* ── Buffer principal de libcurl ─────────────────────────────────────────── */
typedef struct {
    /* Buffer completo de la respuesta (para el path no-streaming) */
    char        *data;
    size_t       len;
    size_t       cap;

    /* Callback de streaming y contexto */
    LLMStreamCb  cb;
    void        *userdata;

    /* Buffer de línea parcial para parsear SSE
     * 65536 evita que líneas SSE largas (args de tool) se corten silenciosamente */
    char         line_buf[65536];
    size_t       line_len;
    int          line_overflow; /* 1 si la línea actual fue truncada */

    /* finish_reason de la última elección */
    char         finish_reason[32];

    /* Acumulación de content tokens durante streaming */
    char        *content_acc;
    size_t       content_len;
    size_t       content_cap;

    /* Acumulación de tool calls durante streaming */
    StreamingToolCall stc[MAX_STREAMING_TOOL_CALLS];
    int               stc_count;

    /* Estado de bloque <think>...</think> inline en content */
    int               in_think_block;
} CurlBuf;

static void buf_init(CurlBuf *b, LLMStreamCb cb, void *ud) {
    memset(b, 0, sizeof(*b));
    b->cap  = 4096;
    b->data = (char *)malloc(b->cap);
    if (b->data) b->data[0] = '\0';
    b->cb       = cb;
    b->userdata = ud;
    b->content_cap = 4096;
    b->content_acc = (char *)malloc(b->content_cap);
    if (b->content_acc) b->content_acc[0] = '\0';
}

static void buf_free(CurlBuf *b) {
    if (b->data)        { free(b->data);        b->data = NULL; }
    if (b->content_acc) { free(b->content_acc); b->content_acc = NULL; }
    for (int i = 0; i < b->stc_count; i++)
        if (b->stc[i].args) { free(b->stc[i].args); b->stc[i].args = NULL; }
}

static void buf_append(CurlBuf *b, const char *src, size_t n) {
    while (b->len + n + 1 > b->cap) { b->cap *= 2; b->data = (char *)realloc(b->data, b->cap); }
    memcpy(b->data + b->len, src, n);
    b->len += n;
    b->data[b->len] = '\0';
}

static void content_acc_append(CurlBuf *b, const char *token) {
    if (!b->content_acc || !token) return;
    size_t tlen = strlen(token);
    while (b->content_len + tlen + 1 > b->content_cap) {
        b->content_cap *= 2;
        b->content_acc = (char *)realloc(b->content_acc, b->content_cap);
        if (!b->content_acc) return;
    }
    memcpy(b->content_acc + b->content_len, token, tlen);
    b->content_len += tlen;
    b->content_acc[b->content_len] = '\0';
}

/* ── Procesar una línea SSE completa ─────────────────────────────────────── */
/*
 * Extrae tanto delta.content (→ callback + acumulación) como
 * delta.tool_calls[i] (→ acumulación de id/name/arguments).
 * Esto espeja la lógica de QueryEngine.ts de Claude Code.
 */
static void sse_process_line(CurlBuf *b, const char *line) {
    if (strncmp(line, "data: ", 6) != 0) return;
    const char *json_str = line + 6;
    if (strcmp(json_str, "[DONE]") == 0) return;

    JSON *root = json_parse(json_str);
    if (!root) return;

    JSON *choices = json_get(root, "choices");
    JSON *choice  = json_index(choices, 0);
    if (!choice) { json_free(root); return; }

    /* ── 0. finish_reason → detectar truncación por max_tokens ─────────── */
    JSON *fr_j = json_get(choice, "finish_reason");
    if (fr_j && fr_j->valuestring && fr_j->valuestring[0])
        snprintf(b->finish_reason, sizeof(b->finish_reason), "%s", fr_j->valuestring);

    JSON *delta = json_get(choice, "delta");
    if (!delta) { json_free(root); return; }

    /* ── 1. delta.content / delta.reasoning_content → tokens ────────── */
    JSON *content   = json_get(delta, "content");
    JSON *reasoning = json_get(delta, "reasoning_content");

    /* 1a. reasoning_content explícito (DeepSeek, etc.) → siempre reasoning */
    if (reasoning && reasoning->valuestring && reasoning->valuestring[0]) {
        const char *rtxt = reasoning->valuestring;
        if (b->cb) {
            /* Prefijo \x01 indica reasoning token al callback */
            size_t rlen = strlen(rtxt);
            char *tagged = (char *)malloc(rlen + 2);
            if (tagged) {
                tagged[0] = '\x01';
                memcpy(tagged + 1, rtxt, rlen);
                tagged[rlen + 1] = '\0';
                b->cb(tagged, b->userdata);
                free(tagged);
            }
        }
        /* No acumular reasoning en content_acc (no va al contexto LLM) */
    }

    /* 1b. delta.content → detectar <think>...</think> inline */
    if (content && content->valuestring && content->valuestring[0]) {
        const char *src = content->valuestring;

        while (*src) {
            if (!b->in_think_block) {
                /* Buscar apertura <think> */
                const char *open = strstr(src, "<think>");
                if (open) {
                    /* Emitir texto antes de <think> como content normal */
                    if (open > src) {
                        size_t pre_len = (size_t)(open - src);
                        char *pre = (char *)malloc(pre_len + 1);
                        if (pre) {
                            memcpy(pre, src, pre_len);
                            pre[pre_len] = '\0';
                            if (b->cb) b->cb(pre, b->userdata);
                            content_acc_append(b, pre);
                            free(pre);
                        }
                    }
                    b->in_think_block = 1;
                    src = open + 7; /* saltar "<think>" */
                } else {
                    /* Sin tag → todo es content normal */
                    if (b->cb) b->cb(src, b->userdata);
                    content_acc_append(b, src);
                    break;
                }
            } else {
                /* Estamos dentro de <think> → buscar cierre */
                const char *close = strstr(src, "</think>");
                if (close) {
                    /* Emitir texto dentro de think como reasoning */
                    if (close > src) {
                        size_t think_len = (size_t)(close - src);
                        char *tagged = (char *)malloc(think_len + 2);
                        if (tagged) {
                            tagged[0] = '\x01';
                            memcpy(tagged + 1, src, think_len);
                            tagged[think_len + 1] = '\0';
                            if (b->cb) b->cb(tagged, b->userdata);
                            free(tagged);
                        }
                    }
                    b->in_think_block = 0;
                    src = close + 8; /* saltar "</think>" */
                } else {
                    /* No hay cierre aún → todo el resto es reasoning */
                    size_t rem_len = strlen(src);
                    if (rem_len > 0) {
                        char *tagged = (char *)malloc(rem_len + 2);
                        if (tagged) {
                            tagged[0] = '\x01';
                            memcpy(tagged + 1, src, rem_len);
                            tagged[rem_len + 1] = '\0';
                            if (b->cb) b->cb(tagged, b->userdata);
                            free(tagged);
                        }
                    }
                    break;
                }
            }
        }
    }

    /* ── 2. delta.tool_calls → acumular fragmentos ───────────────────── */
    JSON *tcs = json_get(delta, "tool_calls");
    if (tcs && tcs->type == JSON_ARRAY) {
        int tc_count = json_array_size(tcs);
        for (int i = 0; i < tc_count; i++) {
            JSON *tc    = json_index(tcs, i);
            JSON *idx_j = json_get(tc, "index");
            int   idx   = idx_j ? idx_j->valueint : i;

            /* Asegurar capacidad */
            if (idx >= MAX_STREAMING_TOOL_CALLS) continue;
            if (idx >= b->stc_count) {
                for (int k = b->stc_count; k <= idx; k++)
                    stc_init(&b->stc[k]);
                b->stc_count = idx + 1;
            }

            StreamingToolCall *stc = &b->stc[idx];

            /* id y name solo llegan en el primer chunk del tool call */
            JSON *id_j = json_get(tc, "id");
            if (id_j && id_j->valuestring && stc->id[0] == '\0') {
                snprintf(stc->id, sizeof(stc->id), "%s", id_j->valuestring);
                LOG("SSE tool_call[%d]: id=%s", idx, stc->id);
            }

            JSON *fn = json_get(tc, "function");
            if (fn) {
                JSON *name_j = json_get(fn, "name");
                if (name_j && name_j->valuestring && stc->name[0] == '\0') {
                    snprintf(stc->name, sizeof(stc->name), "%s", name_j->valuestring);
                    LOG("SSE tool_call[%d]: name=%s", idx, stc->name);
                }

                /* arguments llegan fragmentados — acumular */
                JSON *args_j = json_get(fn, "arguments");
                if (args_j && args_j->valuestring)
                    stc_append_args(stc, args_j->valuestring);
            }
        }
    }

    json_free(root);
}

static size_t curl_write_cb(char *ptr, size_t size, size_t nmemb, void *userdata) {
    CurlBuf *b   = (CurlBuf *)userdata;
    size_t total = size * nmemb;

    /* Acumular en buffer completo (necesario para path no-streaming) */
    buf_append(b, ptr, total);

    /* Parsear líneas SSE si hay callback de streaming */
    if (b->cb) {
        for (size_t i = 0; i < total; i++) {
            char c = ptr[i];
            if (c == '\n') {
                b->line_buf[b->line_len] = '\0';
                if (!b->line_overflow)
                    sse_process_line(b, b->line_buf);
                b->line_len = 0;
                b->line_overflow = 0;
            } else if (c != '\r') {
                if (b->line_len < sizeof(b->line_buf) - 2)
                    b->line_buf[b->line_len++] = c;
                else
                    b->line_overflow = 1; /* línea demasiado larga — descartar */
            }
        }
    }
    return total;
}

/* ── Materializar tool calls acumulados en LLMResult ─────────────────────── */
static void finalize_streaming_tool_calls(CurlBuf *b, LLMResult *result) {
    if (b->stc_count == 0) return;

    LOG("finalize_streaming_tool_calls: %d tool calls acumulados, finish_reason=%s",
        b->stc_count, b->finish_reason[0] ? b->finish_reason : "(vacío)");

    /* Detectar truncación por max_tokens: args JSON incompleto */
    if (strcmp(b->finish_reason, "length") == 0) {
        result->state = LLM_ERROR;
        snprintf(result->error, sizeof(result->error),
                 "Respuesta truncada (finish_reason=length): el modelo agotó max_tokens "
                 "con un tool call incompleto. Aumenta max_tokens o simplifica la tarea.");
        return;
    }

    result->tool_calls = (LLMToolCall *)calloc(b->stc_count, sizeof(LLMToolCall));
    if (!result->tool_calls) return;
    result->tool_call_count = b->stc_count;

    for (int i = 0; i < b->stc_count; i++) {
        StreamingToolCall *stc = &b->stc[i];
        snprintf(result->tool_calls[i].id,   sizeof(result->tool_calls[i].id),   "%s", stc->id);
        snprintf(result->tool_calls[i].name, sizeof(result->tool_calls[i].name), "%s", stc->name);

        /* Validar que los argumentos acumulados son JSON válido */
        if (stc->args && stc->args[0]) {
            JSON *test = json_parse(stc->args);
            if (!test) {
                /* Args malformados — puede ser truncación o bug del modelo */
                result->state = LLM_ERROR;
                snprintf(result->error, sizeof(result->error),
                         "Tool '%s': argumentos JSON malformados/truncados. "
                         "Verifica max_tokens o reinicia la conversación.", stc->name);
                free(result->tool_calls);
                result->tool_calls = NULL;
                result->tool_call_count = 0;
                return;
            }
            json_free(test);
        }

        result->tool_calls[i].arguments     = stc->args;
        result->tool_calls[i].arguments_len = stc->args_len;
        stc->args = NULL; /* transferir propiedad — buf_free no debe liberar */
    }
}

LLMResult llm_chat(const LLMConfig *cfg,
                   const char *messages_json,
                   const char *tools_json,
                   LLMStreamCb cb,
                   void *userdata) {
    LLMResult result;
    memset(&result, 0, sizeof(result));

    LOG("════════ llm_chat INICIO ════════");
    LOG("  endpoint=%s model=%s stream=%d max_tokens=%d",
        cfg->endpoint, cfg->model, cfg->stream, cfg->max_tokens);
    LOG("  messages_json length=%zu", messages_json ? strlen(messages_json) : 0);
    LOG("  tools_json length=%zu", tools_json ? strlen(tools_json) : 0);

    /* Log del system prompt (primer mensaje) para verificar instrucciones */
    if (messages_json) {
        JSON *msgs = json_parse(messages_json);
        if (msgs && msgs->type == JSON_ARRAY) {
            int msg_count = json_array_size(msgs);
            LOG("  mensaje count=%d", msg_count);
            for (int i = 0; i < msg_count; i++) {
                JSON *m = json_index(msgs, i);
                JSON *role = m ? json_get(m, "role") : NULL;
                JSON *cont = m ? json_get(m, "content") : NULL;
                const char *r = role && role->valuestring ? role->valuestring : "?";
                size_t clen = cont && cont->valuestring ? strlen(cont->valuestring) : 0;
                if (strcmp(r, "system") == 0) {
                    LOG("  msg[%d] role=%s len=%zu content=%.500s", i, r, clen,
                        cont && cont->valuestring ? cont->valuestring : "");
                } else {
                    LOG("  msg[%d] role=%s len=%zu preview=%.150s", i, r, clen,
                        cont && cont->valuestring ? cont->valuestring : "(null)");
                }
                /* Log tool_calls en mensajes assistant */
                JSON *tc = m ? json_get(m, "tool_calls") : NULL;
                if (tc && tc->type == JSON_ARRAY) {
                    LOG("  msg[%d] tiene %d tool_calls", i, json_array_size(tc));
                }
            }
            json_free(msgs);
        }
    }

    char *body = build_request_body(cfg, messages_json, tools_json);
    if (!body) {
        LOG("  ERROR: OOM al construir request body");
        result.state = LLM_ERROR;
        snprintf(result.error, sizeof(result.error), "OOM al construir request");
        return result;
    }

    char url[600];
    snprintf(url, sizeof(url), "%s/chat/completions", cfg->endpoint);

    CURL *curl = curl_easy_init();
    if (!curl) {
        free(body);
        LOG("  ERROR: curl_easy_init falló");
        result.state = LLM_ERROR;
        snprintf(result.error, sizeof(result.error), "curl_easy_init falló");
        return result;
    }

    CurlBuf buf;
    buf_init(&buf, cb, userdata);

    struct curl_slist *headers = NULL;
    headers = curl_slist_append(headers, "Content-Type: application/json");
    headers = curl_slist_append(headers, "Accept: text/event-stream");

    curl_easy_setopt(curl, CURLOPT_URL, url);
    curl_easy_setopt(curl, CURLOPT_POST, 1L);
    curl_easy_setopt(curl, CURLOPT_POSTFIELDS, body);
    curl_easy_setopt(curl, CURLOPT_HTTPHEADER, headers);
    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, curl_write_cb);
    curl_easy_setopt(curl, CURLOPT_WRITEDATA, &buf);
    curl_easy_setopt(curl, CURLOPT_TIMEOUT, 0L);
    curl_easy_setopt(curl, CURLOPT_CONNECTTIMEOUT, 10L);

    LOG("  Enviando POST a: %s  body_len=%zu", url, strlen(body));

    CURLcode rc = curl_easy_perform(curl);

    if (rc != CURLE_OK) {
        LOG("  CURL ERROR: %s", curl_easy_strerror(rc));
    } else {
        long http_code = 0;
        curl_easy_getinfo(curl, CURLINFO_RESPONSE_CODE, &http_code);
        LOG("  HTTP STATUS: %ld  response_len=%zu", http_code, buf.len);
    }

    curl_slist_free_all(headers);
    curl_easy_cleanup(curl);
    free(body);

    if (rc != CURLE_OK) {
        result.state = LLM_ERROR;
        snprintf(result.error, sizeof(result.error), "curl: %s", curl_easy_strerror(rc));
        buf_free(&buf);
        return result;
    }

    if (cfg->stream) {
        /* Notificar fin de stream al caller */
        if (cb) cb(NULL, userdata);

        /* Content normal: preferir contenido acumulado por SSE (content_acc).
         * Algunos servidores devuelven la respuesta completa como JSON al final
         * en lugar de emitir SSE tokens. En ese caso buf.content_len==0 pero
         * buf.data contiene el JSON final — soportarlo como fallback. */
        if (buf.content_len > 0 && buf.content_acc) {
            result.content = buf.content_acc;
            buf.content_acc = NULL; /* transferir propiedad */
        } else if (buf.data && buf.len > 0) {
            /* Fallback: parsear JSON completo como en modo no-streaming */
            JSON *root = json_parse(buf.data);
            if (root) {
                JSON *choices = json_get(root, "choices");
                JSON *choice  = json_index(choices, 0);
                if (choice) {
                    JSON *msg     = json_get(choice, "message");
                    JSON *content = msg ? json_get(msg, "content") : NULL;
                    if (content && content->valuestring)
                        result.content = strdup(content->valuestring);
                    parse_tool_calls(choice, &result);
                }
                json_free(root);
            }
        }

        /* Tool calls: materializar desde los acumuladores si no parseados ya */
        if (result.tool_call_count == 0)
            finalize_streaming_tool_calls(&buf, &result);
    } else {
        /* No-streaming: parsear la respuesta JSON completa */
        if (buf.data && buf.len > 0) {
            JSON *root = json_parse(buf.data);
            if (root) {
                JSON *choices = json_get(root, "choices");
                JSON *choice  = json_index(choices, 0);
                if (choice) {
                    JSON *msg     = json_get(choice, "message");
                    JSON *content = msg ? json_get(msg, "content") : NULL;
                    if (content && content->valuestring)
                        result.content = strdup(content->valuestring);
                    parse_tool_calls(choice, &result);
                }
                json_free(root);
            }
        }
    }

    result.state = (result.state == LLM_ERROR) ? LLM_ERROR : LLM_DONE;
    buf_free(&buf);

    LOG("════════ llm_chat RESULTADO ════════");
    LOG("  state=%s", result.state == LLM_DONE ? "DONE" : "ERROR");
    if (result.state == LLM_ERROR)
        LOG("  error=%s", result.error);
    LOG("  content length=%zu preview=%.200s",
        result.content ? strlen(result.content) : 0,
        result.content ? result.content : "(null)");
    LOG("  tool_call_count=%d", result.tool_call_count);
    for (int i = 0; i < result.tool_call_count; i++) {
        LOG("  tool_call[%d]: name='%s' id='%s' args=%.300s",
            i, result.tool_calls[i].name, result.tool_calls[i].id,
            result.tool_calls[i].arguments ? result.tool_calls[i].arguments : "(null)");
    }
    LOG("════════ llm_chat FIN ════════");

    return result;
}

